module top_module(
    input clk,
    input load,
    input [7:0] data_in,
    output [7:0] data_out
);reg [7:0] shift_reg;

      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin
        if (load) begin
            shift_reg <= data_in;
        end else begin
            shift_reg <= {shift_reg[6:0], shift_reg[7]};
        end
    end

    assign data_out = shift_reg;

endmodule
